import{_ as a,c as t,o,aj as r}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"Smart Contracts","description":"","frontmatter":{},"headers":[],"relativePath":"blockchain/wasm.md","filePath":"blockchain/wasm.md","lastUpdated":1777621302000}'),c={name:"blockchain/wasm.md"};function i(n,e,s,l,d,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="smart-contracts" tabindex="-1">Smart Contracts <a class="header-anchor" href="#smart-contracts" aria-label="Permalink to &quot;Smart Contracts&quot;">​</a></h1><p>Iroha transactions execute <code>Executable</code> payloads. The current data model supports:</p><ul><li><code>Executable::Instructions</code>: an ordered set of Iroha Special Instructions</li><li><code>Executable::ContractCall</code>: a by-reference call to a deployed contract instance</li><li><code>Executable::Ivm</code>: Iroha VM bytecode</li><li><code>Executable::IvmProved</code>: Iroha VM bytecode with a precomputed instruction overlay and proof commitments</li></ul><p>Older Iroha 2-era contract examples used legacy helper crates and boxed query snippets. Current Iroha 3 contract work should target the Iroha VM and current SDK builders instead.</p><h2 id="when-to-use-smart-contracts" tabindex="-1">When To Use Smart Contracts <a class="header-anchor" href="#when-to-use-smart-contracts" aria-label="Permalink to &quot;When To Use Smart Contracts&quot;">​</a></h2><p>Use normal instructions when the transaction can be expressed directly:</p><ul><li>register or unregister objects</li><li>mint, burn, or transfer assets</li><li>update metadata</li><li>grant or revoke permissions</li><li>execute a trigger</li><li>set on-chain parameters</li></ul><p>Use a smart contract when the transaction needs packaged logic that is awkward to express as a static instruction sequence, or when a deployed contract instance should be called by reference.</p><h2 id="ivm-executables" tabindex="-1">IVM Executables <a class="header-anchor" href="#ivm-executables" aria-label="Permalink to &quot;IVM Executables&quot;">​</a></h2><p><code>Executable::Ivm</code> carries raw IVM bytecode. Nodes execute that bytecode inside the runtime limits configured for the chain. Keep bytecode small and deterministic; contracts are part of transaction execution and therefore affect consensus.</p><p><code>Executable::IvmProved</code> is intended for proof-carrying flows. It carries:</p><ul><li>IVM bytecode</li><li>a deterministic instruction overlay</li><li>an execution-events commitment</li><li>a gas-policy commitment</li></ul><p>The proof binds the overlay to the executed bytecode. Depending on pipeline policy, validators can verify the proof and replay execution as an additional safety check.</p><h2 id="deployed-contract-calls" tabindex="-1">Deployed Contract Calls <a class="header-anchor" href="#deployed-contract-calls" aria-label="Permalink to &quot;Deployed Contract Calls&quot;">​</a></h2><p><code>Executable::ContractCall</code> invokes a deployed contract instance by address. Use this when contract code is registered separately and transactions should call it by reference instead of carrying the bytecode every time.</p><h2 id="operational-guidance" tabindex="-1">Operational Guidance <a class="header-anchor" href="#operational-guidance" aria-label="Permalink to &quot;Operational Guidance&quot;">​</a></h2><ul><li>Keep contracts deterministic. Contract behavior must not depend on local wall-clock time, host filesystem state, network calls, or other peer-local inputs.</li><li>Keep payloads compact. Large bytecode increases transaction size and block propagation cost.</li><li>Prefer typed instructions for simple ledger changes. They are easier to audit and cheaper to execute.</li><li>Treat contract upgrade and registration permissions as high-risk operational controls.</li></ul><p>See also:</p><ul><li><a href="/iroha-2-docs/blockchain/instructions.html">Instructions</a></li><li><a href="/iroha-2-docs/blockchain/triggers.html">Triggers</a></li><li><a href="/iroha-2-docs/blockchain/permissions.html">Permissions</a></li><li><a href="/iroha-2-docs/reference/data-model-schema.html">Data model schema</a></li></ul>',19)])])}const m=a(c,[["render",i]]);export{u as __pageData,m as default};
